const PROCESSING_FEE = 5;
const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
const BLOCK_OF_THREE_DISCOUNT = 15;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const runeBasePremium = (runeCount: number): number => {
  const ungrouped = runeCount * BASE_PREMIUM.rune;
  return runeCount === 3 ? ungrouped - BLOCK_OF_THREE_DISCOUNT : ungrouped;
};

const sumBasePremiums = (items: Item[]): number => {
  const runes = items.filter((i) => i.type === "rune");
  const others = items.filter((i) => i.type !== "rune");
  const otherBase = others.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
  return runeBasePremium(runes.length) + otherBase;
};
